MERGE INTO CONSULTAS FIN USING (SELECT '000712SubConsEnTransito' INFORME ,TO_CLOB(q'[SELECT  DETALLE_COMPROBANTE_CNT.NRO_DOCUMENTO,DETALLE_COMPROBANTE_CNT.VALOR_DEBITO
        ,DETALLE_COMPROBANTE_CNT.VALOR_CREDITO,DETALLE_COMPROBANTE_CNT.FECHA,DETALLE_COMPROBANTE_CNT.TIPO_CPTE,DETALLE_COMPROBANTE_CNT.COMPROBANTE 
FROM DETALLE_COMPROBANTE_CNT   
    INNER JOIN   TIPO_COMPROBANTE TC
    ON DETALLE_COMPROBANTE_CNT.compania =  TC.compania
    AND DETALLE_COMPROBANTE_CNT.TIPO_CPTE  =  TC.CODIGO
WHERE   DETALLE_COMPROBANTE_CNT.COMPANIA = s$compania$s  
AND     TC.CLASE_CONTABLE  IN (s$strTipos$s)  
AND     DETALLE_COMPROBANTE_CNT.CUENTA = 's$codCuenta$s'  
s$condicion$s 
ORDER BY  
        DETALLE_COMPROBANTE_CNT.TIPO_CPTE, DETALLE_COMPROBANTE_CNT.COMPROBANTE, DETALLE_COMPROBANTE_CNT.CONSECUTIVO]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);